class Solution:
    def maxEnvelopes(self, envelopes):
        n = len(envelopes)
        env = sorted(envelopes)
        best = 0
        dp = [1] * n
        for i in range(n):
            for j in range(i):
                if env[j][0] < env[i][0] and env[j][1] < env[i][1]:
                    if dp[j] + 1 > dp[i]:
                        dp[i] = dp[j] + 1
            if dp[i] > best:
                best = dp[i]
        return best if n else 0

